############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.128) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "parserNumberWithUnits.pl", "contextCurrency.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $name = randomPerson(); $initial = random(4000,5000,5); Context("Currency")->flags->set(trimTrailingZeros => 1); $start = Currency($initial); $rate = random(1.5,2.5,0.01); $speed = Currency($rate); $final = $initial + random(400,1000,5); $end = Currency($final); $solution = ($final - $initial)/$rate; $area = NumberWithUnits("$solution ft^2");
############################################################ # Body ############################################################
BEGIN_PGML [$name]'s annual property tax had been [`[$start]\text{.}`] But [$name->subject] did some renovation to [$name->possessive] house that added more square footage, and now the annual property tax is [`[$end]\text{.}`] The county assesses property tax at a rate of [`[$speed]`] per square foot. How much area did [$name] add to [$name->possessive] home?
[_]{$area}{20}
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
